INSERT INTO "public"."countries" ("id", "code_iso", "name_fr", "name_en", "region", "official_name", "flag_url", "description", "population", "capital", "fsu_established", "fsu_budget", "fsu_coordinator_name", "fsu_coordinator_email", "fsu_coordinator_phone", "logo_path", "created_at", "updated_at", "legal_texts") VALUES
	('d947b5eb-80bb-4265-afe4-adad4f36e4d4', 'gh', 'Ghana', 'Ghana', 'CEDEAO', 'République du Ghana', 'https://flagcdn.com/w320/gh.png', 'Le Ghana a un FSU mature depuis 2017, avec un focus particulier sur l''éducation numérique et les télécentres communautaires. Le programme est cité comme modèle dans la sous-région.', '32,8 millions', 'Accra', '2017', '30 milliards FCFA', 'M. Kwame Mensah', 'fsu@ghana.gov', '+233 30 000 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:32.72452+00', NULL),
	('4866a87c-4369-499c-acbb-587e06748d7a', 'sn', 'Sénégal', 'Senegal', 'CEDEAO', 'République du Sénégal', 'https://flagcdn.com/w320/sn.png', 'Pionnier dans la région, le Sénégal a créé son FSU en 2018 et a obtenu la certification ISO 9001 en 2024. Le programme sénégalais est reconnu pour ses innovations dans les sites solaires autonomes et son modèle de subvention efficace.', '17,4 millions', 'Dakar', '2018', '25 milliards FCFA', 'Mme Fatou Diallo', 'fsu@senegal.gouv', '+221 33 800 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:32.72452+00', NULL),
	('7cf3de43-25ff-430b-a4dc-c051c64102c2', 'mz', 'Mozambique', 'Mozambique', 'SADC', 'République du Mozambique', 'https://flagcdn.com/w320/mz.png', 'Le Mozambique a créé son FSU en 2021 pour connecter les zones rurales après les cyclones. Le programme finance des infrastructures résilientes.', '31,3 millions', 'Maputo', '2021', '22 milliards FCFA', 'M. Carlos Machava', 'fsu@mozambique.mz', '+258 20 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:32.72452+00', NULL),
	('b7114415-09f1-45a4-b081-4c54cf74261a', 'za', 'Afrique du Sud', 'South Africa', 'SADC', 'République d''Afrique du Sud', 'https://flagcdn.com/w320/za.png', 'L''Afrique du Sud dispose d''un FSU mature depuis 2016, finançant des projets de connectivité broadband et de centres numériques communautaires dans les townships.', '60,0 millions', 'Pretoria', '2016', '60 milliards FCFA', 'Mme Thandi Mbeki', 'fsu@southafrica.gov.za', '+27 10 000 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.241951+00', 'Le cadre juridique du Service Universel en Afrique du Sud repose sur la loi sur les communications électroniques (Electronic Communications Act) de 2005. Elle définit le Fonds de Service Universel et d''Accès (USAASA) comme l''organe chargé de gérer les contributions des opérateurs (0,2% du chiffre d''affaires annuel) pour financer le déploiement des infrastructures dans les zones sous-desservies.'),
	('d3077782-c322-400c-8a2c-51b8fbd2a628', 'ci', 'Côte d''Ivoire', 'Ivory Coast', 'CEDEAO', 'République de Côte d''Ivoire', 'https://flagcdn.com/w320/ci.png', 'La Côte d''Ivoire a établi son Fonds de Service Universel en 2019 avec pour mission de connecter 1000 localités rurales d''ici 2026. Le programme se concentre sur la connectivité scolaire, les centres de santé communautaires et l''inclusion numérique des femmes.', '27,5 millions', 'Yamoussoukro', '2019', '20 milliards FCFA', 'Dr. Amani Kouassi', 'fsu@gouv.ci', '+225 27 20 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.241951+00', 'Le cadre juridique du Service Universel en Côte d''Ivoire est régi par l''ordonnance n°2012-293 relative aux Télécommunications et aux Technologies de l''Information et de la Communication. L''ANSUT est chargée de la mise en œuvre des programmes de service universel, financés par une contribution de 2% du chiffre d''affaires des opérateurs titulaires de licences.'),
	('2ff49cae-b29f-4d09-802c-bb31aba2ff7e', 'bj', 'Bénin', 'Benin', 'CEDEAO', 'République du Bénin', 'https://flagcdn.com/w320/bj.png', 'Le Bénin a lancé son Fonds de Service Universel en 2020 pour étendre la connectivité dans les zones rurales et périurbaines. Le programme met l''accent sur le numérique éducatif et les cybercentres communautaires.', '13,7 millions', 'Porto-Novo', '2020', '8 milliards FCFA', 'M. Cossi Houénou', 'fsu@benin.gouv', '+229 21 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('346716f6-50c3-499e-8262-4e606e559ffe', 'bf', 'Burkina Faso', 'Burkina Faso', 'CEDEAO', 'Burkina Faso', 'https://flagcdn.com/w320/bf.png', 'Le Burkina Faso a établi son FSU en 2019 avec pour ambition de réduire la fracture numérique dans les zones rurales. Le programme finance des projets de connectivité broadband et des centres numériques de proximité.', '22,1 millions', 'Ouagadougou', '2019', '12 milliards FCFA', 'M. Abdoulaye Sawadogo', 'fsu@burkina.gouv', '+226 25 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('7bd90175-43f1-4a48-9e36-7898b30c4a3a', 'cv', 'Cap-Vert', 'Cape Verde', 'CEDEAO', 'République du Cap-Vert', 'https://flagcdn.com/w320/cv.png', 'Le Cap-Vert, pays insulaire, a créé son FSU en 2021 pour garantir l''accès aux télécommunications sur l''ensemble de ses îles. Le programme priorise la connectivité inter-îles et les services numériques maritimes.', '0,6 millions', 'Praia', '2021', '3 milliards FCFA', 'Mme Maria Santos', 'fsu@caboverde.gov', '+238 260 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('d61c7e1e-1ac6-4d15-864d-115da6032ba7', 'gm', 'Gambie', 'Gambia', 'CEDEAO', 'République de Gambie', 'https://flagcdn.com/w320/gm.png', 'La Gambie a initié son FSU en 2022 pour connecter les communautés rurales le long du fleuve Gambie. Le programme cible les écoles, les centres de santé et les marchés ruraux.', '2,6 millions', 'Banjul', '2022', '2 milliards FCFA', 'M. Lamin Jammeh', 'fsu@gambia.gov', '+220 400 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('8c90a2a9-8f70-4e98-b40f-ace2e6e6389b', 'gn', 'Guinée', 'Guinea', 'CEDEAO', 'République de Guinée', 'https://flagcdn.com/w320/gn.png', 'La Guinée a mis en place son FSU en 2020 pour développer la connectivité dans les zones enclavées du pays. Le programme se concentre sur le déploiement de la fibre optique et les centres multimédia communautaires.', '13,9 millions', 'Conakry', '2020', '10 milliards FCFA', 'M. Mamadou Bah', 'fsu@guinee.gov', '+224 620 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('c1f52831-9ddf-40a6-bc73-a293d017998a', 'gw', 'Guinée-Bissau', 'Guinea-Bissau', 'CEDEAO', 'République de Guinée-Bissau', 'https://flagcdn.com/w320/gw.png', 'La Guinée-Bissau a lancé son FSU en 2023 avec le soutien de partenaires internationaux. Le programme vise à étendre la couverture mobile et les services numériques de base dans les régions intérieures.', '2,1 millions', 'Bissau', '2023', '1,5 milliard FCFA', 'M. Braima Sanhá', 'fsu@guinebissau.gov', '+245 320 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('3b85da8f-673b-45ab-b169-331dbf7043ee', 'lr', 'Libéria', 'Liberia', 'CEDEAO', 'République du Libéria', 'https://flagcdn.com/w320/lr.png', 'Le Libéria a établi son FSU en 2021 dans le cadre de la reconstruction post-conflit. Le programme finance l''extension des réseaux mobiles et la connectivité des établissements publics dans les comtés ruraux.', '5,4 millions', 'Monrovia', '2021', '4 milliards FCFA', 'Mme Grace Freeman', 'fsu@liberia.gov', '+231 880 000 000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('7662f35c-a341-43f1-b5c9-d09d23cc145c', 'ml', 'Mali', 'Mali', 'CEDEAO', 'République du Mali', 'https://flagcdn.com/w320/ml.png', 'Le Mali a créé son FSU en 2018 pour lutter contre la fracture numérique dans les vastes zones sahéliennes. Le programme soutient les cybercentres ruraux et la connectivité des services de santé et d''éducation.', '22,6 millions', 'Bamako', '2018', '15 milliards FCFA', 'M. Oumar Traoré', 'fsu@mali.gov', '+223 70 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('46eba4c4-b0ca-4022-915e-abbacc4f9d5b', 'ne', 'Niger', 'Niger', 'CEDEAO', 'République du Niger', 'https://flagcdn.com/w320/ne.png', 'Le Niger a mis en place son FSU en 2020 pour connecter les vastes zones sahariennes et sahéliennes du pays. Le programme priorise la couverture mobile rurale et les solutions numériques pour l''éducation et la santé.', '27,2 millions', 'Niamey', '2020', '8 milliards FCFA', 'M. Issaka Abdou', 'fsu@niger.gov', '+227 90 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('43a4dd5f-750e-43e9-8be5-d14e4af254af', 'ng', 'Nigeria', 'Nigeria', 'CEDEAO', 'République Fédérale du Nigeria', 'https://flagcdn.com/w320/ng.png', 'Le Nigeria dispose du plus grand FSU d''Afrique de l''Ouest, créé en 2016. Le programme finance le déploiement de la fibre optique, la connectivité broadband et les projets pilotes 5G. Il coute les zones non desservies et sous-desservies du territoire national.', '223,8 millions', 'Abuja', '2016', '120 milliards FCFA', 'M. Chukwu Eze', 'fsu@nigeria.gov.ng', '+234 800 000 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('9984edb2-67a5-4fcb-8cd2-3739b6fe97cf', 'sl', 'Sierra Leone', 'Sierra Leone', 'CEDEAO', 'République de Sierra Leone', 'https://flagcdn.com/w320/sl.png', 'La Sierra Leone a lancé son FSU en 2022 pour accélérer l''inclusion numérique après la période post-Ebola. Le programme finance les télécentres communautaires et la connectivité des établissements scolaires.', '8,6 millions', 'Freetown', '2022', '3 milliards FCFA', 'M. Ibrahim Kamara', 'fsu@sierraleone.gov', '+232 76 000 000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('b050ce65-58b3-4f68-8c5d-644a20cdd01f', 'tg', 'Togo', 'Togo', 'CEDEAO', 'République Togolaise', 'https://flagcdn.com/w320/tg.png', 'Le Togo a créé son FSU en 2019 avec une vision ambitieuse de transformation numérique. Le programme finance des projets de connectivité rurale, des espaces numériques de coworking et l''e-administration dans les préfectures.', '8,8 millions', 'Lomé', '2019', '7 milliards FCFA', 'Mme Afi Mensah', 'fsu@togo.gouv', '+228 22 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('f03b776f-8a8e-4ab1-95d6-d3d8845f7e44', 'cm', 'Cameroun', 'Cameroon', 'CEEAC', 'République du Cameroun', 'https://flagcdn.com/w320/cm.png', 'Le Cameroun a établi son FSU en 2017 pour réduire la fracture numérique entre zones urbaines et rurales. Le programme finance le déploiement de la fibre optique et les centres multimédia communautaires dans les régions enclavées.', '28,6 millions', 'Yaoundé', '2017', '18 milliards FCFA', 'M. Paul Nganou', 'fsu@cameroun.gov', '+237 6 00 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('4d844e0f-5083-4c87-a8af-b4697150a3df', 'cf', 'Centrafrique', 'Central African Republic', 'CEEAC', 'République centrafricaine', 'https://flagcdn.com/w320/cf.png', 'La Centrafrique a initié son FSU en 2022 avec l''appui de partenaires internationaux pour reconstruire les infrastructures de télécommunication. Le programme cible la connectivité des zones post-conflit et les services numériques de base.', '5,7 millions', 'Bangui', '2022', '2,5 milliards FCFA', 'M. Jean-Bédel Bango', 'fsu@centrafrique.gov', '+236 70 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('c6315886-ed21-4941-b353-9780d29f011c', 'td', 'Tchad', 'Chad', 'CEEAC', 'République du Tchad', 'https://flagcdn.com/w320/td.png', 'Le Tchad a créé son FSU en 2021 pour étendre la couverture télécom dans les vastes zones sahariennes et sahéliennes. Le programme priorise la connectivité des services publics et les solutions satellitaires pour les zones isolées.', '18,3 millions', 'N''Djamena', '2021', '5 milliards FCFA', 'M. Hassan Mahamat', 'fsu@tchad.gov', '+235 66 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('14579777-28d6-46e8-82d0-6f664a53be0a', 'cg', 'Congo', 'Congo', 'CEEAC', 'République du Congo', 'https://flagcdn.com/w320/cg.png', 'Le Congo a établi son FSU en 2019 pour développer la connectivité dans les zones forestières et rurales. Le programme finance la fibre optique le long du fleuve Congo et les centres numériques départementaux.', '5,8 millions', 'Brazzaville', '2019', '6 milliards FCFA', 'M. Guy Okemba', 'fsu@congo.gov', '+242 06 000 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('0e5086fe-5c73-4900-bdf7-7967dcc084fc', 'ga', 'Gabon', 'Gabon', 'CEEAC', 'République gabonaise', 'https://flagcdn.com/w320/ga.png', 'Le Gabon a créé son FSU en 2018 pour accélérer la transformation numérique du pays. Le programme finance la connectivité broadband, les réseaux urbains et les projets d''inclusion numérique dans les provinces.', '2,4 millions', 'Libreville', '2018', '10 milliards FCFA', 'Mme Nadine Ondo', 'fsu@gabon.gov', '+241 01 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('cdbc6568-7633-470a-b7f2-47a64bbf8758', 'gq', 'Guinée équatoriale', 'Equatorial Guinea', 'CEEAC', 'République de Guinée équatoriale', 'https://flagcdn.com/w320/gq.png', 'La Guinée équatoriale a lancé son FSU en 2022 pour étendre la connectivité sur l''île de Bioko et dans la région continentale. Le programme finance les infrastructures de télécommunication et les services numériques.', '1,7 millions', 'Malabo', '2022', '4 milliards FCFA', 'M. Teodoro Obiang Jr.', 'fsu@guineaecuatorial.gov', '+240 333 000 000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('66fe379c-e25d-4320-b21d-5881f0412dec', 'st', 'Sao Tomé-et-Principe', 'São Tomé and Príncipe', 'CEEAC', 'République démocratique de Sao Tomé-et-Principe', 'https://flagcdn.com/w320/st.png', 'Sao Tomé-et-Principe a initié son FSU en 2023 pour garantir l''accès universel aux télécommunications sur les deux îles. Le programme cible la connectivité broadband et les services numériques publics.', '0,2 millions', 'Sao Tomé', '2023', '1 milliard FCFA', 'M. Carlos Neves', 'fsu@saotome.gov', '+239 222 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('7dc54d18-a13c-4f75-b6a7-0d85cf99cba4', 'bi', 'Burundi', 'Burundi', 'EAC', 'République du Burundi', 'https://flagcdn.com/w320/bi.png', 'Le Burundi a créé son FSU en 2021 pour étendre la connectivité dans les collines et les zones rurales densément peuplées. Le programme finance les cybercentres communautaires et la connectivité des établissements scolaires.', '13,2 millions', 'Gitega', '2021', '3 milliards FCFA', 'M. Pierre Ndayishimiye', 'fsu@burundi.gov', '+257 79 000 000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('fad2387a-3245-4566-966f-c63111f6ea2a', 'km', 'Comores', 'Comoros', 'EAC', 'Union des Comores', 'https://flagcdn.com/w320/km.png', 'Les Comores ont établi leur FSU en 2022 pour connecter les quatre îles de l''archipel. Le programme priorise la connectivité inter-îles par fibre sous-marine et les services numériques pour les populations isolées.', '0,9 millions', 'Moroni', '2022', '1,5 milliard FCFA', 'M. Ahmed Soilihi', 'fsu@comores.gov', '+269 770 0000', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
	('f3d66f78-9572-4260-aa3e-41c7e69acd6f', 'dj', 'Djibouti', 'Djibouti', 'EAC', 'République de Djibouti', 'https://flagcdn.com/w320/dj.png', 'Djibouti a lancé son FSU en 2020 pour tirer parti de sa position stratégique de hub de câbles sous-marins. Le programme finance la connectivité des zones intérieures et les services numériques pour les populations nomades.', '1,1 millions', 'Djibouti', '2020', '2 milliards FCFA', 'M. Omar Farah', 'fsu@djibouti.gov', '+253 77 00 00 00', NULL, '2026-05-12 11:51:32.72452+00', '2026-05-12 11:51:33.039226+00', NULL),
