	('34df62f7-5645-4a8a-810e-58a2eaeb1e4d', '{"ar": "تحسين الهياكل الأساسية ذات النطاق العريض", "en": "Upgrading of broadband infrastructure", "fr": "Modernisation de l''''infrastructure haut débit", "pt": "Modernização da infra-estrutura de banda larga"}', '{"ar": "نشر كابلات الألياف البصرية الجديدة عبر زامبيا.", "en": "Deployment of new fibre optic cables across Zambia.", "fr": "Déploiement de nouveaux câbles à fibre optique à travers Zambie.", "pt": "Implantação de novos cabos de fibra óptica na Zâmbia."}', '{"ar": "♦ محتوى المادة التفصيلي: تحسين البنية التحتية ذات النطاق العريض. (لوريم بيسوم دولور) يجلس على الخوذة", "en": "<p>Detailed content for the article: Upgrade of broadband infrastructure. Lorem ipsum dolor sit amet...</p>", "fr": "<p>Contenu détaillé pour l''article : Modernisation de l''''infrastructure haut débit. Lorem ipsum dolor sit amet...</p>", "pt": "<p>Conteúdo detalhado para o artigo: Atualização da infraestrutura de banda larga. Lorem ipsum dolor sit amet...</p>"}', '{"ar": "الهياكل الأساسية", "en": "Infrastructure", "fr": "Infrastructure", "pt": "Infra-estruturas"}', 'USF-ADC', 'https://images.unsplash.com/photo-1544620347-c4fd4a3d5957?auto=format&fit=crop&q=80&w=800', '2026-02-07 18:47:24.032168+00', true, NULL, NULL, 'fr', NULL, '2026-05-02 18:48:08.467153+00', '2026-05-04 10:21:25.838433+00', 'published', '', '', '', '', 0, false, true, NULL, '99824537-dd3e-4999-898f-eef526492db3'),
	('d0000000-0000-0000-0000-000000000005', '{"ar": "التقرير السنوي 2025: سنة واحدة للتقدم", "en": "Annual Report 2025: One Year of Progress", "fr": "Rapport annuel 2025 : Un an de progrès", "pt": "Relatório Anual 2025: Um Ano de Progresso"}', '{"ar": "Review of UAT activities for 2025.", "en": "Review of UAT activities for 2025.", "fr": "Bilan des activités de l''UAT pour l''année 2025.", "pt": "Revisão das atividades da UAT para 2025."}', '{"ar": "ويمثل التقرير السنوي لعام 2025 خطوة هامة في تطوير الاتصالات السلكية واللاسلكية في أفريقيا. الكشف عن الأرقام الرئيسية والمشاريع الرئيسية للسنة", "en": "The 2025 Annual Report marks a significant step in the development of telecommunications in Africa. Discover key figures and key projects for the year.</p>", "fr": "<p>Le rapport annuel 2025 marque une étape significative dans le développement des télécommunications en Afrique. Découvrez les chiffres clés et les projets marquants de l''année.</p>", "pt": "O Relatório Anual de 2025 marca um passo significativo no desenvolvimento das telecomunicações em África. Descubra valores-chave e projetos-chave para o ano.</p>"}', '{"ar": "التقرير", "en": "report", "fr": "rapport", "pt": "relatório"}', 'UAT', 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=1200', '2026-04-19 08:14:17.863291+00', true, 'UAT Communication', '6 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:33:15.718721+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000001', '{"ar": "إطلاق صندوق الخدمات الشاملة للبلدان الأفريقية", "en": "Launch of the Pan-African Universal Service Fund", "fr": "Lancement du Fonds de Service Universel pan-africain", "pt": "Lançamento do Fundo de Serviço Universal Pan-Africano"}', '{"ar": "مبادرة تاريخية لسد الفجوة الرقمية في أفريقيا.", "en": "A historic initiative to bridge the digital divide in Africa.", "fr": "Une initiative historique pour combler la fracture numérique en Afrique.", "pt": "Uma iniciativa histórica para superar a divisão digital em África."}', '{"ar": "يعلن الاتحاد الأفريقي للاتصالات السلكية واللاسلكية إنشاء صندوق خدمات عالمي قاري. والغرض من هذا الصندوق هو تمويل الهياكل الأساسية للاتصالات السلكية واللاسلكية في المناطق غير المحمية في أفريقيا", "en": "The African Telecommunications Union announces the creation of a continental universal service fund. This fund is intended to finance telecommunications infrastructure in unserved areas of Africa.</p>", "fr": "<p>L''Union Africaine des Télécommunications annonce la création d''un fonds de service universel à l''échelle continentale. Ce fonds vise à financer les infrastructures de télécommunications dans les zones non desservies d''Afrique.</p>", "pt": "A União Africana das Telecomunicações anuncia a criação de um fundo de serviço universal continental. Este fundo destina-se a financiar infra-estruturas de telecomunicações em zonas não servidas de África.</p>"}', '{"ar": "التمويل", "en": "financing", "fr": "financement", "pt": "financiamento"}', 'UAT', 'https://images.unsplash.com/photo-1556761175-b413da4baf72?w=1200', '2026-04-12 08:14:17.863291+00', true, 'UAT Communication', '5 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:35:07.548285+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('452d573f-981f-47d4-87c7-1963b1d9f1c4', '{"ar": "توسيع الشبكة المتنقلة في المناطق النائية", "en": "Extension of mobile network in remote areas", "fr": "Extension du réseau mobile dans les zones isolées", "pt": "Extensão da rede móvel em áreas remotas"}', '{"ar": "رُكبت هوائيات جديدة بفضل صندوق الخدمات العالمي.", "en": "New relay antennas installed thanks to the Universal Service Fund.", "fr": "De nouvelles antennes relais installées grâce au Fonds de Service Universel.", "pt": "Novas antenas de relé instaladas graças ao Universal Service Fund."}', '{"ar": "محتوى مفصَّل للمادة: توسيع الشبكة المتنقلة في المناطق النائية. (لوريم بيسوم دولور) يجلس على الخوذة", "en": "<p>Detailed content for article: Extension of mobile network in remote areas. Lorem ipsum dolor sit amet...</p>", "fr": "<p>Contenu détaillé pour l''article : Extension du réseau mobile dans les zones isolées. Lorem ipsum dolor sit amet...</p>", "pt": "<p>Conteúdo detalhado para artigo: Extensão da rede móvel em áreas remotas. Lorem ipsum dolor sit amet...</p>"}', '{"ar": "الهاتف", "en": "Telephone", "fr": "Téléphonie", "pt": "Telefone"}', 'USF-ADC', 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=800', '2026-02-06 18:47:24.030974+00', true, NULL, NULL, 'fr', NULL, '2026-05-02 18:48:08.031145+00', '2026-05-04 10:23:17.083707+00', 'published', '', '', '', '', 0, false, true, NULL, '33392bf1-8998-45bd-8e4b-4ab72dfa3abd'),
	('511ae2d5-0050-47a8-90b7-61b417ccb84b', '{"ar": "رقمنة الخدمات العامة المحلية في كوت ديفوار", "en": "Digitalisation of local public services in Côte d''Ivoire", "fr": "Digitalisation des services publics de proximité en Côte d''Ivoire", "pt": "Digitalização dos serviços públicos locais na Costa do Marfim"}', '{"ar": "ترافق وحدة الدعم الفني (FSU) البلديات في مصر في مسار التحول الرقمي.", "en": "The FSU accompanies the municipalities of Egypt in their digital transformation.", "fr": "Le FSU accompagne les communes de Égypte dans leur transformation numérique.", "pt": "A FSU acompanha os municípios do Egito em sua transformação digital."}', '{"ar": "- محتوى مفصَّل للمادة: رقمنة الخدمات العامة المحلية. (لوريم بيسوم دولور) يجلس على الخوذة", "en": "<p>Detailed content for the article: Digitalization of local public services. Lorem ipsum dolor sit amet...</p>", "fr": "<p>Contenu détaillé pour l''article : Digitalisation des services publics de proximité. Lorem ipsum dolor sit amet...</p>", "pt": "Conteúdo detalhado para o artigo: Digitalização de serviços públicos locais. Lorem ipsum dolor sit amet...</p>"}', '{"ar": "E-Gouv", "en": "E-Gouv", "fr": "E-Gouv", "pt": "E-Gouv"}', 'USF-ADC', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&q=80&w=800', '2026-04-30 18:47:24.033442+00', true, NULL, NULL, 'fr', NULL, '2026-05-02 18:48:08.93241+00', '2026-05-07 16:57:24.702451+00', 'published', '', '', '', '', 0, false, true, NULL, '0ab2ec37-4634-4185-a417-2c62d24117e2'),
	('d0000000-0000-0000-0000-000000000009', '{"ar": "التعليم الرقمي في شرق أفريقيا", "en": "Digital education in East Africa", "fr": "L''éducation numérique en Afrique de l''Est", "pt": "Educação digital em África Oriental"}', '{"ar": "مبادرات التعليم الرقمي في منطقة ABC.", "en": "Initiatives for Digital Education in the ABC Region.", "fr": "Initiatives pour l''éducation numérique dans la région EAC.", "pt": "Iniciativas para a Educação Digital na Região ABC."}', '{"ar": "وتطلق بلدان جماعة شرق أفريقيا مبادرات مشتركة لتعزيز التعليم الرقمي في المدارس الريفية", "en": "The East African Community countries are launching joint initiatives to promote digital education in rural schools.</p>", "fr": "<p>Les pays de la Communauté d''Afrique de l''Est lancent des initiatives conjointes pour promouvoir l''éducation numérique dans les écoles rurales.</p>", "pt": "Os países da Comunidade da África Oriental estão a lançar iniciativas conjuntas para promover a educação digital nas escolas rurais.</p>"}', '{"ar": "التعليم", "en": "education", "fr": "éducation", "pt": "educação"}', 'UAT-EAC', 'https://images.unsplash.com/photo-1509062522246-3755977927d7?w=1200', '2026-04-23 08:14:17.863291+00', true, 'Bureau EAC', '6 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:31:44.796812+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000002', '{"ar": "الشراكة مع البنك الدولي", "en": "Partnership with the World Bank", "fr": "Partenariat avec la Banque Mondiale", "pt": "Parceria com o Banco Mundial"}', '{"ar": "اتفاق تمويل قدره 500 مليون دولار من دولارات الولايات المتحدة للهياكل الأساسية.", "en": "Funding agreement of USD 500 million for infrastructure.", "fr": "Accord de financement de 500 millions USD pour les infrastructures.", "pt": "Acordo de financiamento de 500 milhões de dólares para infra-estruturas."}', '{"ar": "والبنك الدولي ملتزم بدعم مشاريع الاتصال في 15 بلدا أفريقيا ذات الأولوية. This funding will allow 10,000 km of fibre optics to be deployed", "en": "The World Bank is committed to supporting connectivity projects in 15 priority African countries. This funding will allow 10,000 km of fibre optics to be deployed.</p>", "fr": "<p>La Banque Mondiale s''engage à soutenir les projets de connectivité dans 15 pays africains prioritaires. Ce financement permettra le déploiement de 10 000 km de fibre optique.</p>", "pt": "O Banco Mundial está empenhado em apoiar projetos de conectividade em 15 países africanos prioritários. Este financiamento permitirá mobilizar 10 000 km de fibra óptica.</p>"}', '{"ar": "الشراكة", "en": "partnership", "fr": "partenariat", "pt": "parceria"}', 'UAT', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=1200', '2026-04-15 08:14:17.863291+00', true, 'UAT Communication', '4 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:34:38.649498+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000014', '{"ar": "الزراعة الرقمية في منطقة سيدياو", "en": "Digital agriculture in the Cedeao area", "fr": "L''agriculture numérique en zone Cedeao", "pt": "Agricultura digital na área de Cedeao"}', '{"ar": "The digital transformation of agriculture in West Africa.", "en": "The digital transformation of agriculture in West Africa.", "fr": "La transformation numérique de l''agriculture en Afrique de l''Ouest.", "pt": "A transformação digital da agricultura na África Ocidental."}', '{"ar": "وتتيح مشاريع الربط في المناطق الريفية الممولة من صندوق الولايات المتحدة تطوير حلول زراعية رقمية", "en": "Rural connectivity projects funded by the USF allow the development of digital farming solutions.</p>", "fr": "<p>Les projets de connectivité rurale financés par le FSU permettent le développement de solutions d''agriculture numérique.</p>", "pt": "Projetos de conectividade rural financiados pela USF permitem o desenvolvimento de soluções agrícolas digitais.</p>"}', '{"ar": "الزراعة", "en": "agriculture", "fr": "agriculture", "pt": "agricultura"}', 'UAT', 'https://www.vivafrik.com/wp-content/uploads/2025/02/Benin-Le-numerique-pourrait-generer-309-millions-pour-lagriculture-dici-a-2028-selon-la-GSMA.jpg', '2026-04-26 14:14:17.863291+00', true, 'Bureau CEDEAO', '5 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:21:31.501396+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000012', '{"ar": "بناء القدرات: البرنامج 2026-2030", "en": "Capacity-building: Programme 2026-2030", "fr": "Renforcement des capacités : Programme 2026-2030", "pt": "Desenvolvimento de capacidades: Programa 2026-2030"}', '{"ar": "The new UAT capacity-building programme.", "en": "The new UAT capacity-building programme.", "fr": "Le nouveau programme de renforcement des capacités de l''UAT.", "pt": "O novo programa de reforço das capacidades da UET."}', '{"ar": "ويبدأ برنامج التدريب الطموح لـ 000 10 من المهنيين في مجال الاتصالات السلكية واللاسلكية بحلول عام 2030", "en": "The UAT is launching an ambitious training programme for 10,000 telecommunications professionals by 2030.</p>", "fr": "<p>L''UAT lance un programme ambitieux de formation de 10 000 professionnels des télécommunications d''ici 2030.</p>", "pt": "A UAT está lançando um ambicioso programa de treinamento para 10.000 profissionais de telecomunicações até 2030.</p>"}', '{"ar": "التدريب", "en": "training", "fr": "formation", "pt": "formação"}', 'UAT', 'https://filetsociaux-ci.org/wp-content/uploads/2026/04/20260401_175157-1024x576.jpg', '2026-04-26 08:14:17.863291+00', true, 'UAT Formation', '4 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:21:52.587119+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000010', '{"ar": "التمويل الابتكاري: سندات المنطقة البيضاء", "en": "Innovative financing: White area bonds", "fr": "Financement innovant : Les obligations zones blanches", "pt": "Financiamento inovador: obrigações de área branca"}', '{"ar": "How the deployment obligations fund the FSU.", "en": "How the deployment obligations fund the FSU.", "fr": "Comment les obligations de déploiement financent le FSU.", "pt": "Como as obrigações de implantação financiam a FSU."}', '{"ar": ":: تمثل السندات المتعلقة بالمناطق المغلقة آلية تمويل مبتكرة لصناديق الخدمات العالمية", "en": "<p>White area cover bonds represent an innovative funding mechanism for the Universal Service Funds.</p>", "fr": "<p>Les obligations de couverture zones blanches représentent un mécanisme de financement innovant pour les Fonds de Service Universel.</p>", "pt": "As obrigações de cobertura da área branca representam um mecanismo de financiamento inovador para os Fundos de Serviço Universal.</p>"}', '{"ar": "التمويل", "en": "financing", "fr": "financement", "pt": "financiamento"}', 'UAT', 'https://images.unsplash.com/photo-1554224155-8d04cb21cd6c?w=1200', '2026-04-24 08:14:17.863291+00', true, 'Jean-Pierre Mbengue', '7 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:31:23.916213+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000007', '{"ar": "التواصل الريفي: النموذج السنغالي", "en": "Rural connectivity: The Senegalese model", "fr": "Connectivité des zones rurales : Le modèle sénégalais", "pt": "Conectividade rural: O modelo senegalês"}', '{"ar": "How Senegal succeededs in the challenge of rural connectivity.", "en": "How Senegal succeeds in the challenge of rural connectivity.", "fr": "Comment le Sénégal réussit le défi de la connectivité rurale.", "pt": "Como o Senegal é bem sucedido no desafio da conectividade rural."}', '{"ar": "تقدم السنغال نموذجا ابتكاريا لنشر الهياكل الأساسية في المناطق الريفية، استنادا إلى شراكة فعالة بين القطاعين العام والخاص", "en": "Senegal presents an innovative model for the deployment of infrastructure in rural areas, based on an effective public-private partnership.</p>", "fr": "<p>Le Sénégal présente un modèle innovant de déploiement d''infrastructures dans les zones rurales, basé sur un partenariat public-privé efficace.</p>", "pt": "O Senegal apresenta um modelo inovador para a implantação de infra-estruturas nas zonas rurais, baseado numa parceria público-privada eficaz.</p>"}', '{"ar": "دراسة", "en": "study", "fr": "étude", "pt": "estudo"}', 'UAT', 'https://images.unsplash.com/photo-1531403009284-440f080d1e12?w=1200', '2026-04-21 08:14:17.863291+00', true, 'Marie Kouassi', '8 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:32:26.399067+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000016', '{"ar": "الصناعة الرقمية: المنافسة 2026", "en": "Digital Entrepreneurship: Competition 2026", "fr": "Entreprenariat numérique : Concours 2026", "pt": "Empreendedorismo Digital: Competição 2026"}', '{"ar": "إطلاق مسابقة تنظيم المشاريع الرقمية.", "en": "Launch of the UAT Digital Entrepreneurship Competition.", "fr": "Lancement du concours d''entreprenariat numérique de l''UAT.", "pt": "Lançamento do Concurso de Empreendedorismo Digital da UAT."}', '{"ar": "وتبدأ شركة UAT منافستها في مجال تنظيم المشاريع الرقمية لدعم بدء العمل في قطاع الاتصالات السلكية واللاسلكية", "en": "The UAT is launching its digital entrepreneurship competition to support start-ups in the telecommunications sector.</p>", "fr": "<p>L''UAT lance son concours d''entreprenariat numérique pour soutenir les start-ups du secteur des télécommunications.</p>", "pt": "A UAT está lançando sua competição de empreendedorismo digital para apoiar startups no setor de telecomunicações.</p>"}', '{"ar": "المنافسة", "en": "competition", "fr": "concours", "pt": "concorrência"}', 'UAT', 'https://pouvoirsafrique.com//uploads/imported_images/uploads/2017/01/start-up-afrik.jpg', '2026-04-26 20:14:17.863291+00', true, 'UAT Innovation', '4 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:20:31.804311+00', 'published', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000003', '{"ar": "تدريب مراكز التنسيق", "en": "Training of Focal Points", "fr": "Formation des Points Focaux", "pt": "Formação de Pontos Focais"}', '{"ar": "First successful training session in Ouagadougou.", "en": "First successful training session in Ouagadougou.", "fr": "Première session de formation réussie à Ouagadougou.", "pt": "Primeira sessão de treino bem sucedida em Ouagadougou."}', '{"ar": "وشارك 25 جهة تنسيق من 10 بلدان مختلفة في التدريب على استخدام منبر اتحاد الولايات المتحدة - لجنة المساعدة الإنمائية. وتمثل هذه الدورة بداية برنامج لبناء القدرات", "en": "25 focal points from 10 different countries participated in the training on the use of the USF-ADC platform. This session marks the beginning of a capacity-building programme.</p>", "fr": "<p>25 points focaux de 10 pays différents ont participé à la formation sur l''utilisation de la plateforme USF-ADC. Cette session marque le début d''un programme de renforcement des capacités.</p>", "pt": "25 pontos focais de 10 países diferentes participaram no treinamento sobre o uso da plataforma USF-ADC. Esta sessão marca o início de um programa de reforço de capacidades.</p>"}', '{"ar": "التدريب", "en": "training", "fr": "formation", "pt": "formação"}', 'UAT', 'https://images.unsplash.com/photo-1524178232363-1fb2b075b655?w=1200', '2026-04-17 08:14:17.863291+00', true, 'UAT Formation', '3 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:34:16.942101+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('2068ca6c-9a09-4db6-aa96-c2d390695f03', '{"en": "Launch of an e-education platform", "fr": "Lancement d''''une plateforme de e-éducation"}', '{"en": "Free access to educational resources for all schools in Eritrea.", "fr": "Accès gratuit à des ressources éducatives pour toutes les écoles de Érythrée."}', '{"en": "Detailed content for the article: Launch of an e-education platform. Lorem ipsum dolor sit amet...", "fr": "Contenu détaillé pour l''article : Lancement d''''une plateforme de e-éducation. Lorem ipsum dolor sit amet..."}', '{"en": "Education", "fr": "Éducation"}', 'USF-ADC', 'https://images.unsplash.com/photo-1501504905252-473c47e087f8?auto=format&fit=crop&q=80&w=800', '2025-07-11 18:47:24.030927+00', true, NULL, NULL, 'fr', NULL, '2026-05-02 18:48:08.011023+00', '2026-05-02 18:48:08.011023+00', 'published', NULL, NULL, NULL, NULL, 0, false, true, NULL, '33392bf1-8998-45bd-8e4b-4ab72dfa3abd'),
	('d0000000-0000-0000-0000-000000000008', '{"ar": "الجمعية العامة 2026: المقررات الرئيسية", "en": "General Assembly 2026: Key Decisions", "fr": "Assemblée Générale 2026 : Les décisions clés", "pt": "Assembleia Geral 2026: Decisões-chave"}', '{"ar": "محاضر الجمعية العامة في كيغالي.", "en": "Minutes of the Kigali General Assembly.", "fr": "Compte rendu de l''Assemblée Générale de Kigali.", "pt": "Minutos da Assembleia Geral de Kigali."}', '{"ar": "واتخذت الجمعية العامة 2026 عدة قرارات هامة لمستقبل الاتصالات السلكية واللاسلكية في أفريقيا. تحقق من الأصوات والقرارات الرئيسية", "en": "General Assembly 2026 took several important decisions for the future of telecommunications in Africa. Check out the main votes and resolutions.</p>", "fr": "<p>L''Assemblée Générale 2026 a pris plusieurs décisions importantes pour l''avenir des télécommunications en Afrique. Découvrez les principaux votes et résolutions.</p>", "pt": "A Assembleia Geral 2026 tomou várias decisões importantes para o futuro das telecomunicações em África. Confira os principais votos e resoluções.</p>"}', '{"ar": "مناسبة", "en": "event", "fr": "évènement", "pt": "evento"}', 'UAT', 'https://images.unsplash.com/photo-1515187029135-18ee286d815b?w=1200', '2026-04-22 08:14:17.863291+00', true, 'UAT Communication', '4 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:54:16.524007+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
	('d0000000-0000-0000-0000-000000000011', '{"ar": "مشروع نيجيري الرائد", "en": "Infrastructure 5G: Nigeria''s Pilot Project", "fr": "Infrastructure 5G : Le projet pilote du Nigeria", "pt": "Infraestrutura 5G: Projeto-piloto da Nigéria"}', '{"ar": "وتشرع نيجيريا في تنفيذ مشروعها الأول في لاغوس.", "en": "Nigeria is launching its first 5G project in Lagos.", "fr": "Le Nigeria lance son premier projet 5G à Lagos.", "pt": "A Nigéria está lançando seu primeiro projeto 5G em Lagos."}', '{"ar": "وتصبح نيجيريا أول بلد في المنطقة يشرع في تنفيذ مشروع تجريبي مدته 5 زاي بدعم من صندوق الخدمات العالمي", "en": "Nigeria becomes the first country in the region to launch a 5G pilot project with support from the Universal Service Fund.</p>", "fr": "<p>Le Nigeria devient le premier pays de la région à lancer un projet pilote 5G avec le soutien du Fonds de Service Universel.</p>", "pt": "A Nigéria torna-se o primeiro país da região a lançar um projeto piloto 5G com apoio do Fundo Universal de Serviço.</p>"}', '{"ar": "الابتكار", "en": "innovation", "fr": "innovation", "pt": "inovação"}', 'Délégué Nigeria', 'https://borgenproject.org/wp-content/uploads/FindingGLAMs_in_Nigeria_FUNAAB07_05_12_970000.jpeg', '2026-04-25 08:14:17.863291+00', true, 'Délégué Nigeria', '5 min', 'fr', NULL, '2026-04-27 08:14:17.863291+00', '2026-05-04 09:22:15.234933+00', 'draft', '', '', '', '', 0, false, true, NULL, NULL),
