	('e17532b0-7756-48c6-a861-34930570027c', '{"ar": "دليل قدرة الحكومة على مواجهة السايبر", "en": "Cyber Resilience Guide for Government", "fr": "Guide de Cyber-résilience pour les administrations publiques", "pt": "Guia de Resistência Cibernética para o Governo"}', '{"ar": "دليل عملي لتعزيز أمن الهياكل الأساسية الحيوية.", "en": "A practical guide to enhancing critical infrastructure security.", "fr": "Un guide pratique pour renforcer la sécurité des infrastructures critiques.", "pt": "Um guia prático para reforçar a segurança das infra-estruturas críticas."}', '{"ar": "التقنية", "en": "technical", "fr": "technical", "pt": "técnico"}', 'doc_collaboration_1.pdf', '/co-redaction/docs/doc_collaboration_1.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-03-28 20:27:33.243753+00', '2026-04-07 20:27:33.243753+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>دليل المرونة الإلكترونية للحكومات</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء شركة UAT Experts.</p><p>دليل عملي لتعزيز أمن البنية التحتية الحيوية.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>E-Resilience Guide for Government</h1><p>This document is the result of a collaboration between UAT experts.</p><p>A practical guide to enhancing critical infrastructure security.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Guide de Cyber-résilience pour les administrations publiques</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Un guide pratique pour renforcer la sécurité des infrastructures critiques.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Guia de Resiliência Digital para Governos</h1><p>Este documento é o resultado da colaboração entre especialistas da UAT.</p><p>Um guia prático para melhorar a segurança de infraestruturas críticas.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-06 13:27:33.243753+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('94ddedfb-cac8-43e7-8774-7881ac75f691', '{"ar": "تقرير متوقع: منظمة العفو الدولية من أجل التنمية المستدامة", "en": "Prospective Report: AI for Sustainable Development", "fr": "Rapport de Prospective : L''IA au service du développement durable", "pt": "Relatório prospectivo: IA para o desenvolvimento sustentável"}', '{"ar": "تحليل متعمق لفرص الذكاء الاصطناعي للقارة الأفريقية.", "en": "In-depth analysis of AI opportunities for the African continent.", "fr": "Analyse approfondie des opportunités de l''IA pour le continent africain.", "pt": "Análise aprofundada das oportunidades da IA para o continente africano."}', '{"ar": "السياسة العامة", "en": "policy", "fr": "policy", "pt": "política"}', 'doc_collaboration_2.pdf', '/co-redaction/docs/doc_collaboration_2.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-03-28 20:27:33.243788+00', '2026-04-07 20:27:33.243788+00', NULL, 0, NULL, 'active', NULL, '{"ar": "تقرير متوقع: AI for Sustainable Development/h1< وهذه الوثيقة ناتجة عن التعاون فيما بين الخبراء التابعين للجامعة. The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization", "en": "<h1>Prospective Report: AI for Sustainable Development</h1><p>This document is the result of collaboration among UAT experts.</p><p>In-depth analysis of AI opportunities for the African continent.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Rapport de Prospective : L''IA au service du développement durable</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Analyse approfondie des opportunités de l''IA pour le continent africain.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "Relatório prospectivo: IA para Desenvolvimento Sustentável</h1><p> Este documento é o resultado da colaboração entre especialistas em TAU.</p><p>Análise aprofundada das oportunidades de IA para o continente africano.</p><h2>1. Introdução</h2><p> A importância desse tópico não está mais para ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-06 05:27:33.243788+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('27a5b017-1fb5-47b8-bc0f-137e8af8c9c3', '{"ar": "السياسة المنسقة للخصوصيات", "en": "Harmonised Privacy Policy", "fr": "Politique Harmonisée de Protection de la Vie Privée", "pt": "Política de Privacidade Harmonizada"}', '{"ar": "سياسة شاملة لضمان امتثال المواطنين وحمايتهم.", "en": "Comprehensive policy to ensure compliance and protection of citizens.", "fr": "Politique globale visant à assurer la conformité et la protection des citoyens.", "pt": "Política global para garantir o cumprimento e a protecção dos cidadãos."}', '{"ar": "السياسة العامة", "en": "policy", "fr": "policy", "pt": "política"}', 'doc_collaboration_4.pdf', '/co-redaction/docs/doc_collaboration_4.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-12 20:27:33.243851+00', '2026-04-22 20:27:33.243851+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>سياسة الخصوصية الموحدة</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء UAT.</p><p>سياسة عالمية لضمان الامتثال وحماية المواطنين.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>Harmonized Privacy Policy</h1><p>This document is the result of collaboration between UAT experts.</p><p>Global policy to ensure compliance and protection of citizens.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Politique Harmonisée de Protection de la Vie Privée</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Politique globale visant à assurer la conformité et la protection des citoyens.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Política de Privacidade Harmonizada</h1><p>Este documento é o resultado da colaboração entre especialistas da UAT.</p><p>Política global para garantir a conformidade e a proteção dos cidadãos.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-21 14:27:33.243851+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('ab1ce658-641b-48d4-86d0-01ba31ba02ab', '{"ar": "إطار الحوكمة السيادية", "en": "Sovereign Cloud Governance Framework", "fr": "Cadre de Gouvernance Cloud Souverain", "pt": "Quadro de Governação Soberana da Nuvem"}', '{"ar": "توصيات لتطوير البنية التحتية السحابية الوطنية.", "en": "Recommendations for the development of national cloud infrastructure.", "fr": "Recommandations pour la mise en place d''infrastructures cloud nationales.", "pt": "Recomendações para o desenvolvimento de infraestrutura nacional em nuvem."}', '{"ar": "النفقات", "en": "carryovers", "fr": "reports", "pt": "transições"}', 'doc_collaboration_7.pdf', '/co-redaction/docs/doc_collaboration_7.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-03-29 20:27:33.243943+00', '2026-04-08 20:27:33.243943+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>إطار حوكمة السحابة السيادية</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء المحكمة الإدارية الموحدة (UAT).</p><p>توصيات لتطوير البنية التحتية الوطنية للحوسبة السحابية.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>Sovereign Cloud Governance Framework</h1><p>This document is the result of collaboration between UAT experts.</p><p>Recommendations for the development of national cloud infrastructure.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Cadre de Gouvernance Cloud Souverain</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Recommandations pour la mise en place d''infrastructures cloud nationales.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Sovereign Cloud Governance Framework</h1><p>Este documento é o resultado da colaboração entre especialistas da UAT.</p><p>Recomendações para o desenvolvimento da infraestrutura nacional de nuvem.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-08 16:27:33.243943+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('d9e2ade4-0c18-4235-ae3e-0d01869e88c7', '{"ar": "الاتفاقية النموذجية للبيانات فيما بين الدول", "en": "Model Inter-State Data Convention", "fr": "Modèle de Convention Inter-étatique sur les données", "pt": "Modelo Convenção Inter-Estatal sobre os Dados"}', '{"ar": "نموذج موحد لتيسير اتفاقات تقاسم البيانات بين البلدان.", "en": "A standardized model to facilitate data sharing agreements between countries.", "fr": "Un modèle standardisé pour faciliter les accords de partage de données entre pays.", "pt": "Um modelo padronizado para facilitar acordos de compartilhamento de dados entre países."}', '{"ar": "القانون", "en": "legal", "fr": "legal", "pt": "legal"}', 'doc_collaboration_3.pdf', '/co-redaction/docs/doc_collaboration_3.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-11 20:27:33.24382+00', '2026-04-21 20:27:33.24382+00', NULL, 0, NULL, 'active', NULL, '{"ar": "○ اتفاقية بيانات الدول() وهذه الوثيقة هي نتيجة للتعاون بين الخبراء التابعين لشركة UAT Experts./p>p ofA نموذج موحد لتسهيل اتفاقات تقاسم البيانات بين البلدان. The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization", "en": "<h1>Inter-State Data Convention Template</h1><p>This document is the result of collaboration between UAT experts.</p><p>A standardized model to facilitate data sharing agreements between countries.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Modèle de Convention Inter-étatique sur les données</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Un modèle standardisé pour faciliter les accords de partage de données entre pays.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "Modelo da Convenção de Dados Interestatais</h1><p> Este documento é resultado da colaboração entre especialistas em TAU.</p><p>Um modelo padronizado para facilitar acordos de compartilhamento de dados entre países.</p><h2>1. Introdução</h2><p> A importância desse tópico não está mais para ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-20 04:27:33.24382+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('a50ca8bd-4bac-4313-aae8-77d9bfc518e3', '{"ar": "بروتوكول تبادل البيانات الصحية في غرب أفريقيا", "en": "Health Data Exchange Protocol in West Africa", "fr": "Protocole d''Échange de Données Santé en Afrique de l''Ouest", "pt": "Protocolo de Intercâmbio de Dados em Saúde na África Ocidental"}', '{"ar": "معايير التشغيل المتبادل لنظم معلومات المستشفيات.", "en": "Interoperability standards for hospital information systems.", "fr": "Standards d''interopérabilité pour les systèmes d''information hospitaliers.", "pt": "Normas de interoperabilidade para sistemas de informação hospitalar."}', '{"ar": "التقنية", "en": "technical", "fr": "technical", "pt": "técnico"}', 'doc_collaboration_6.pdf', '/co-redaction/docs/doc_collaboration_6.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-15 20:27:33.243912+00', '2026-04-25 20:27:33.243912+00', NULL, 0, NULL, 'active', NULL, '{"ar": "بروتوكول تبادل البيانات المتعلقة بالصحة في غرب أفريقيا/H1 وهذه الوثيقة ناتجة عن التعاون بين الخبراء التابعين لشركة UAT Experts. The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization", "en": "<h1>Health Data Exchange Protocol in West Africa</h1><p>This document is the result of collaboration among UAT experts.</p><p>Interoperability standards for hospital information systems.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Protocole d''Échange de Données Santé en Afrique de l''Ouest</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Standards d''interopérabilité pour les systèmes d''information hospitaliers.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Protocolo de Intercâmbio de Dados de Saúde na África Ocidental</h1><p> Este documento é resultado da colaboração entre es