	('92e64816-f815-4494-8502-2af7a8c17876', '{"ar": "الاستراتيجية القارية للأمن السيبراني", "en": "Cybersecurity Continental Strategy", "fr": "Stratégie Continentale de Cybersécurité", "pt": "Estratégia Continental de Cibersegurança"}', '{"ar": "خطة عمل للتصدّي المنسق للتهديدات السيبرانية.", "en": "Action plan for a coordinated response to cyber threats.", "fr": "Plan d''action pour une réponse coordonnée aux cybermenaces.", "pt": "Plano de acção para uma resposta coordenada às ameaças cibernéticas."}', '{"ar": "النماذج", "en": "templates", "fr": "templates", "pt": "modelos"}', 'doc_collaboration_9.pdf', '/co-redaction/docs/doc_collaboration_9.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-10 20:27:33.244009+00', '2026-04-20 20:27:33.244009+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>استراتيجية الأمن السيبراني القارية</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء المحكمة الإدارية الموحدة (UAT).</p><p>خطة عمل للاستجابة المنسقة للتهديدات السيبرانية.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>Cybersecurity Continental Strategy</h1><p>This document is the result of collaboration among UAT experts.</p><p>Action plan for a coordinated response to cyber threats.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Stratégie Continentale de Cybersécurité</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Plan d''action pour une réponse coordonnée aux cybermenaces.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Estratégia Continental de Cibersegurança</h1><p>Este documento é o resultado da colaboração entre especialistas da UAT.</p><p>Plano de ação para uma resposta coordenada às ameaças cibernéticas.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-19 02:27:33.244009+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('0fe08d6b-d959-4362-a213-bae7cef04b28', '{"ar": "معيار الربط عبر الحدود 2025", "en": "Transborder Connectivity Standard 2025", "fr": "Standard de Connectivité Transfrontalière 2025", "pt": "Norma de Conectividade Transfronteiriça 2025"}', '{"ar": "المواصفات التقنية لترابط الشبكات الإقليمية.", "en": "Technical specifications for interconnection of regional networks.", "fr": "Spécifications techniques pour l''interconnexion des réseaux régionaux.", "pt": "Especificações técnicas para a interconexão das redes regionais."}', '{"ar": "معلومات عامة", "en": "general", "fr": "general", "pt": "geral"}', 'doc_collaboration_5.pdf', '/co-redaction/docs/doc_collaboration_5.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-12 20:27:33.243883+00', '2026-04-22 20:27:33.243883+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>معيار الاتصال العابر للحدود 2025</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء UAT.</p><p>المواصفات التقنية لربط الشبكات الإقليمية.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>Transborder Connectivity Standard 2025</h1><p>This document is the result of collaboration among UAT experts.</p><p>Technical specifications for the interconnection of regional networks.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Standard de Connectivité Transfrontalière 2025</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Spécifications techniques pour l''interconnexion des réseaux régionaux.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Padrão de Conectividade Transfronteiriça 2025</h1><p>Este documento é o resultado da colaboração entre especialistas da UAT.</p><p>Especificações técnicas para a interconexão das redes regionais.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-22 13:27:33.243883+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('7e1f0222-5eda-45b8-963c-bdc6a7e1c892', '{"ar": "ميثاق التحول الرقمي في أفريقيا", "en": "Charter of Digital Transformation in Africa", "fr": "Charte de la Transformation Digitale en Afrique", "pt": "Carta de Transformação Digital em África"}', '{"ar": "وثيقة تعاونية تحدد الاتجاهات الاستراتيجية للتحول الرقمي.", "en": "A collaborative document defining the strategic directions of digital transformation.", "fr": "Document collaboratif définissant les axes stratégiques de la transformation numérique.", "pt": "Um documento colaborativo definindo as direções estratégicas da transformação digital."}', '{"ar": "السياسة العامة", "en": "policy", "fr": "policy", "pt": "política"}', 'doc_collaboration_0.pdf', '/co-redaction/docs/doc_collaboration_0.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-03 20:27:33.243673+00', '2026-04-13 20:27:33.243673+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>ميثاق التحول الرقمي في أفريقيا</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء UAT.</p><p>وثيقة تعاونية تحدد الاتجاهات الاستراتيجية للتحول الرقمي.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>Charter of Digital Transformation in Africa</h1><p>This document is the result of collaboration between UAT experts.</p><p>Collaborative document defining the strategic directions of digital transformation.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Charte de la Transformation Digitale en Afrique</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Document collaboratif définissant les axes stratégiques de la transformation numérique.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Carta de Transformação Digital em África</h1><p>Este documente é o resultado da colaboração entre especialistas da UAT.</p><p>Documento colaborativo que define as direções estratégicas da transformação digital.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', NULL, NULL, 'closed', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL, NULL, '2026-04-12 04:27:33.243673+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL),
	('86765ab8-c468-4a44-adf8-a09b34ec8e5f', '{"ar": "الكتاب الأبيض حول البلوك تشين المواطن", "en": "White Paper on the Citizen Blockchain", "fr": "Livre Blanc sur la Blockchain Citoyenne", "pt": "Livro Branco sobre a Blockchain Cidadã"}', '{"ar": "(ب) استكشاف حالات استخدام الخناق للخدمات العامة.", "en": "Exploration of blockchain usage cases for public services.", "fr": "Exploration des cas d''usage de la blockchain pour les services publics.", "pt": "Exploração de casos de uso de blockchain para serviços públicos."}', '{"ar": "النفقات", "en": "carryovers", "fr": "reports", "pt": "transições"}', 'doc_collaboration_8.pdf', '/co-redaction/docs/doc_collaboration_8.pdf', NULL, 'application/pdf', true, NULL, 'fr', NULL, NULL, false, '2026-04-20 20:27:33.243977+00', '2026-04-30 20:27:33.243977+00', NULL, 0, NULL, 'active', NULL, '{"ar": "<h1>الكتاب الأبيض حول بلوك تشين المواطن</h1><p>هذه الوثيقة هي نتيجة تعاون بين خبراء المحكمة الإدارية الموحدة (UAT).</p><p>استكشاف حالات استخدام البلوك تشين في الخدمات العامة.</p><h2>1. المقدمة</h2><p>لم تعد أهمية هذا الموضوع بحاجة إلى إثبات في السياق الحالي للتسريع الرقمي.</p>", "en": "<h1>Citizen Blockchain White Paper</h1><p>This document is the result of collaboration between UAT experts.</p><p>Exploration of blockchain use cases for public services.</p><h2>1. Introduction</h2><p>The importance of this topic is no longer to be demonstrated in the current context of accelerated digitization.</p>", "fr": "<h1>Livre Blanc sur la Blockchain Citoyenne</h1><p>Ce document est le résultat d''une collaboration entre experts de l''UAT.</p><p>Exploration des cas d''usage de la blockchain pour les services publics.</p><h2>1. Introduction</h2><p>L''importance de ce sujet n''est plus à démontrer dans le contexte actuel de numérisation accélérée.</p>", "pt": "<h1>Livro Branco sobre a Blockchain Cidadã</h1><p>Este documento é o resultado da colaboração entre especialistas da UAT.</p><p>Exploração de casos de uso da blockchain para serviços públicos.</p><h2>1. Introdução</h2><p>A importância deste tema já não precisa ser demonstrada no contexto atual de digitalização acelerada.</p>"}', '691c96a8-ab0b-4b49-9d60-1fa2960a4ad7', '2026-05-15 13:24:27.865+00', 'editing', '691c96a8-ab0b-4b49-9d60-1fa2960a4ad7', NULL, NULL, '2026-04-29 10:27:33.243977+00', '25d550fb-d861-468e-ab5b-523af4cc2b7c', '25d550fb-d861-468e-ab5b-523af4cc2b7c', NULL);
