INSERT INTO "public"."faq_articles" ("id", "title", "content", "category", "sort_order", "is_published", "created_at", "updated_at") VALUES
	('01d610c9-4574-4971-b116-3378d8170e6a', 'Comment créer un compte ?', 'Pour créer un compte, cliquez sur le bouton "S''inscrire" en haut à droite de la page. Remplissez le formulaire avec vos informations et validez votre adresse email.', 'general', 1, true, '2026-05-12 11:51:33.030752+00', '2026-05-12 11:51:33.030752+00'),
	('d0af6476-35b3-404f-b6f5-513f3224891e', 'Comment réinitialiser mon mot de passe ?', 'Cliquez sur "Mot de passe oublié" sur la page de connexion. Entrez votre adresse email et suivez les instructions envoyées par email.', 'account', 1, true, '2026-05-12 11:51:33.030752+00', '2026-05-12 11:51:33.030752+00'),
	('d879d98e-d71c-47cc-ba93-f74091ca4ad7', 'Qu''est-ce qu''une soumission FSU ?', 'Une soumission FSU (Forum des Syndicats Unifiés) est un document ou une information soumise par votre syndicat pour partage et validation.', 'fsu', 1, true, '2026-05-12 11:51:33.030752+00', '2026-05-12 11:51:33.030752+00'),
	('b2d1cc5c-1469-407a-85f0-106e8be1c9e1', 'Comment soumettre un document FSU ?', 'Allez dans la section FSU, cliquez sur "Nouvelle soumission", remplissez le formulaire et ajoutez vos pièces jointes.', 'fsu', 2, true, '2026-05-12 11:51:33.030752+00', '2026-05-12 11:51:33.030752+00');
