	('69d1efb7-0c87-4fa2-85ef-89038efe0d1e', '{"ar": "إعلان: إصدار جديد من المنصة", "en": "Announcement: New version of the platform", "fr": "Annonce : Nouvelle version de la plateforme", "pt": "Anúncio: Nova versão da plataforma"}', '{"ar": "الإصدار 2.0 من منصة USF-ADC أصبح متاحًا الآن مع العديد من الميزات الجديدة.", "en": "Version 2.0 of the USF-ADC platform is now online with many new features.", "fr": "La version 2.0 de la plateforme USF-ADC est maintenant en ligne avec de nombreuses nouvelles fonctionnalités.", "pt": "A versão 2.0 da plataforma USF-ADC já está online com العديد de novas funcionalidades."}', 'fc7ca789-0af2-4590-938e-6cf5528b16a1', NULL, true, false, true, 0, 'open', '2026-05-09 11:51:32.950343+00', '2026-05-13 14:19:21.88262+00'),
	('b3287487-9166-45ba-aff7-ac0d8053ed0e', '{"ar": "استخدام تقنية الجيل الخامس (5G) لصالح صندوق الخدمة الشاملة (FSU)", "en": "Use of 5G for the FSU", "fr": "Utilisation de la 5G pour le FSU", "pt": "Utilização da 5G para o FSU"}', '{"ar": "هل لديكم مشاريع لنشر شبكة الجيل الخامس (5G) باستخدام موارد صندوق الخدمة الشاملة (FSU)؟ شاركوا التفاصيل والتحديات التي واجهتموها.", "en": "Do you have any 5G deployment projects using FSU resources? Share details and challenges encountered.", "fr": "Avez-vous des projets de déploiement 5G utilisant les ressources du FSU ? Partagez les détails et les défis rencontrés.", "pt": "Têm projetos de implementação de 5G utilizando recursos do FSU? Partilhem os detalhes e os desafios encontrados."}', '5840db8b-f668-48ff-bd00-55d4c9c7b03c', NULL, false, false, true, 0, 'open', '2026-04-27 11:51:32.950343+00', '2026-05-13 14:20:03.564829+00'),
	('c3ba683d-ffc6-40eb-be96-0c2eccc4b8b5', '{"ar": "حوكمة صندوق الخدمة الشاملة (FSU)", "en": "FSU governance", "fr": "Gouvernance des FSU", "pt": "Governança do FSU"}', '{"ar": "كيف يمكن ضمان حوكمة جيدة لصناديق الخدمة الشاملة على المستوى الوطني؟", "en": "How can good governance of Universal Service Funds be ensured at the national level?", "fr": "Comment garantir une bonne gouvernance des Fonds de Service Universel au niveau national ?", "pt": "Como garantir uma boa governação dos Fundos de Serviço Universal a nível nacional?"}', 'e86081d5-cac2-4fc6-b979-5234fdb55c59', NULL, false, false, true, 0, 'open', '2026-05-05 11:51:32.950343+00', '2026-05-13 14:20:16.985676+00'),
	('8c3325b0-26bf-4250-9c3d-49c1f5c7fa4a', '{"ar": "اتصال ريفي فعال", "en": "Effective rural connectivity", "fr": "Connectivité rurale efficace", "pt": "Conectividade rural eficaz"}', '{"ar": "ما هو الحل الأكثر فعالية من حيث التكلفة لربط المناطق الريفية؟ نرحب بتجاربكم وآرائكم.", "en": "What is the most cost-effective solution for connecting rural areas? Experience feedback is welcome.", "fr": "Quelle est la solution la plus rentable pour connecter les zones rurales ? Retours d''expérience bienvenus.", "pt": "Qual é a solução mais rentável para ligar as zonas rurais? Partilhas de experiências são bem-vindas."}', '5840db8b-f668-48ff-bd00-55d4c9c7b03c', NULL, true, false, true, 1, 'open', '2026-05-02 11:51:32.950343+00', '2026-05-15 12:09:12.404385+00'),
	('27795320-863d-4e17-af6d-c34a13756a43', '{"ar": "استراتيجيات تمويل صندوق الخدمة الشاملة (FSU)", "en": "FSU financing strategies", "fr": "Stratégies de financement du FSU", "pt": "Estratégias de financiamento do FSU"}', '{"ar": "ما هي أفضل الممارسات لتعبئة موارد صندوق الخدمة الشاملة؟ شاركوا تجاربكم واستراتيجياتكم الناجحة.", "en": "What are the best practices for mobilizing Universal Service Fund resources? Share your experiences and successful strategies.", "fr": "Quelles sont les meilleures pratiques pour mobiliser les ressources du Fonds de Service Universel ? Partagez vos expériences et vos stratégies réussies.", "pt": "Quais são as melhores práticas para mobilizar os recursos do Fundo de Serviço Universal? Partilhem as vossas experiências e estratégias bem-sucedidas."}', '31d663d6-a739-412c-a32b-0eb39f44c07c', NULL, false, false, true, 0, 'open', '2026-04-17 11:51:32.950343+00', '2026-05-13 14:18:41.991545+00'),
	('609f37eb-e352-4224-ba79-1c3d830504ff', '{"ar": "مشاكل الوصول إلى المنصة", "en": "Platform access issues", "fr": "Problèmes d''accès à la plateforme", "pt": "Problemas de acesso à plataforma"}', '{"ar": "أواجه صعوبات في تسجيل الدخول إلى المنصة. كيف يمكنني حل هذه المشكلة؟", "en": "I am having difficulties logging into the platform. How can I resolve this issue?", "fr": "Je rencontre des difficultés pour me connecter à la plateforme. Comment puis-je résoudre ce problème ?", "pt": "Estou a ter dificuldades em aceder à plataforma. Como posso resolver este problema?"}', 'fc7ca789-0af2-4590-938e-6cf5528b16a1', NULL, false, false, true, 0, 'solved', '2026-04-22 11:51:32.950343+00', '2026-05-13 14:19:08.527837+00'),
	('b2c7b728-b1a8-4fdb-9152-dd4e01026da1', '{"ar": "الشراكة بين القطاعين العام والخاص في قطاع الاتصالات", "en": "PPP partnership in the telecom sector", "fr": "Partenariat PPP dans le secteur des télécoms", "pt": "Parceria PPP no setor das telecomunicações"}', '{"ar": "أمثلة على شراكات ناجحة بين القطاعين العام والخاص في مجال الاتصالات في أفريقيا.", "en": "Examples of successful public-private partnerships in telecommunications in Africa.", "fr": "Exemples de partenariats public-privé réussis pour les télécommunications en Afrique.", "pt": "Exemplos de parcerias público-privadas bem-sucedidas no setor das telecomunicações em África."}', '31d663d6-a739-412c-a32b-0eb39f44c07c', NULL, false, false, true, 0, 'open', '2026-05-07 11:51:32.950343+00', '2026-05-13 14:19:49.424672+00'),
	('4743b5f9-109d-49a4-ba84-af82689de6de', '{"ar": "مرحبًا بكم في منتدى USF-ADC", "en": "Welcome to the USF-ADC forum", "fr": "Bienvenue sur le forum USF-ADC", "pt": "Bem-vindo ao fórum USF-ADC"}', '{"ar": "مرحبًا بكم في المنتدى العام لمنصة USF-ADC! هذه المنصة مخصصة للتعاون وتبادل الخبرات بين نقاط الاتصال وخبراء صناديق الخدمة الشاملة في أفريقيا. لا تترددوا في طرح أسئلتكم ومشاركة خبراتكم.", "en": "Welcome to the public forum of the USF-ADC platform! This platform is dedicated to collaboration and exchange of experiences between focal points and Universal Service Fund experts in Africa. Feel free to ask your questions and share your expertise.", "fr": "Bienvenue sur le forum public de la plateforme USF-ADC ! Cette plateforme est dédiée à la collaboration et à l''échange d''expériences entre les points focaux et les experts des Fonds de Service Universel en Afrique. N''hésitez pas à poser vos questions et à partager vos expertise.", "pt": "Bem-vindos ao fórum público da plataforma USF-ADC! Esta plataforma é dedicada à colaboração e à troca de experiências entre os pontos focais e os especialistas dos Fundos de Serviço Universal em África. Não hesitem em fazer perguntas e partilhar as vossas experiências."}', 'fc7ca789-0af2-4590-938e-6cf5528b16a1', NULL, true, false, true, 0, 'open', '2026-04-12 11:51:32.950343+00', '2026-05-13 14:18:55.122647+00');
INSERT INTO "public"."forum_posts" ("id", "topic_id", "created_by", "content", "is_solution", "created_at", "updated_at") VALUES
	('152963b8-f530-4417-8acd-86394e1d1bad', 'b3287487-9166-45ba-aff7-ac0d8053ed0e', NULL, '{"ar": "أطلقنا مشروعًا تجريبيًا لشبكة 5G في نيجيريا بدعم من صندوق الخدمة الشاملة (FSU). النتائج واعدة جدًا.", "en": "We launched a 5G pilot project in Nigeria with the support of the FSU. The results are very promising.", "fr": "Nous avons lancé un projet pilote 5G au Nigeria avec le soutien du FSU. Les résultats sont très prometteurs.", "pt": "Lançámos um projeto piloto 5G na Nigéria com o apoio do FSU. Os resultados são muito promissores."}', false, '2026-04-28 11:51:32.950343+00', '2026-05-13 14:13:31.457779+00'),
	('5d312ec3-60df-417c-aa7a-0daaf9119c6c', '27795320-863d-4e17-af6d-c34a13756a43', NULL, '{"ar": "بالتأكيد! في السنغال، استخدمنا نموذجًا مختلطًا بنجاح. يساهم المشغلون من القطاع الخاص بنسبة 30٪ من التمويل.", "en": "Absolutely! In Senegal, we used a mixed model successfully. Private operators contribute 30% of the funding.", "fr": "Absolument ! Au Sénégal, nous avons utilisé un modèle mixte avec succès. Les opérateurs privés contribuent 30% du financement.", "pt": "Absolutamente! No Senegal, utilizámos um modelo misto com sucesso. Os operadores privados contribuem com 30% do financiamento."}', true, '2026-04-19 11:51:32.950343+00', '2026-05-13 14:13:46.142519+00'),
	('777070b7-b2d1-4076-8e7e-e81b7cec1eae', '609f37eb-e352-4224-ba79-1c3d830504ff', NULL, '{"ar": "هل تحققت من اتصالك بالإنترنت؟ حاول مسح ذاكرة التخزين المؤقت للمتصفح.", "en": "Have you checked your internet connection? Try clearing your browser cache.", "fr": "Avez-vous vérifié votre connexion internet ? Essayez de vider le cache de votre navigateur.", "pt": "Você verificou a sua conexão à internet? Tente limpar o cache do seu navegador."}', false, '2026-04-23 11:51:32.950343+00', '2026-05-13 14:13:59.104456+00'),
	('a0e94955-e240-4713-82ad-424fc7d0feee', '8c3325b0-26bf-4250-9c3d-49c1f5c7fa4a', NULL, '{"ar": "تظل الألياف البصرية الحل الأكثر فعالية للمناطق الريفية، رغم التكاليف الأولية المرتفعة.", "en": "Fiber optics remains the most effective solution for rural areas, despite high initial costs.", "fr": "La fibre optique reste la solution la plus efficace pour les zones rurales, malgré les coûts initiaux élevés.", "pt": "A fibra ótica continua a ser a solução mais eficaz para as zonas rurais, apesar dos elevados custos iniciais."}', false, '2026-05-03 11:51:32.950343+00', '2026-05-13 14:14:16.814878+00'),
	('a800594e-78b5-4e09-b97e-58ed48986ea2', '8c3325b0-26bf-4250-9c3d-49c1f5c7fa4a', NULL, '{"ar": "حسنًا، لكن هل أخذتم بعين الاعتبار حلول الاتصالات عبر الأقمار الصناعية للمناطق النائية جدًا؟", "en": "Okay, but have you considered satellite solutions for very remote areas?", "fr": "D''accord, mais avez-vous considéré les solutions par satellite pour les zones très reculées ?", "pt": "Está bem, mas já consideraram soluções por satélite para zonas muito remotas?"}', false, '2026-05-04 11:51:32.950343+00', '2026-05-13 14:14:32.576135+00'),
	('af7c6727-f62d-4e6f-acd0-ae38d213e9c8', 'b2c7b728-b1a8-4fdb-9152-dd4e01026da1', NULL, '{"ar": "في كينيا، مكّن الشراكة بين القطاعين العام والخاص مع شركة Safaricom من توسيع تغطية شبكات الهاتف المحمول لتشمل 85٪ من البلاد.", "en": "In Kenya, the PPP partnership with Safaricom has enabled mobile coverage to be extended to 85% of the country.", "fr": "Au Kenya, le partenariat PPP avec Safaricom a permis d''étendre la couverture mobile à 85% du pays.", "pt": "No Quénia, a parceria PPP com a Safaricom permitiu expandir a cobertura móvel para 85% do país."}', false, '2026-05-08 11:51:32.950343+00', '2026-05-13 14:14:47.374853+00'),
	('dad39dc2-494f-4b02-b41d-ccf930d60f48', '27795320-863d-4e17-af6d-c34a13756a43', NULL, '{"ar": "من خلال تجربتي، من الضروري دمج التمويل الحكومي مع الاستثمارات الخاصة لتعظيم موارد صندوق الخدمة الشاملة (FSU).", "en": "From my experience, it is crucial to combine government funding with private investment to maximize FSU resources.", "fr": "De mon expérience, il est crucial de combiner le financement gouvernemental avec les investissements privés pour maximiser les ressources du FSU.", "pt": "Da minha experiência, é crucial combinar o financiamento governamental com investimentos privados para maximizar os recursos do FSU."}', false, '2026-04-18 11:51:32.950343+00', '2026-05-13 14:15:04.754868+00'),
	('fb689596-b18f-416d-a265-3140a99d54cd', '609f37eb-e352-4224-ba79-1c3d830504ff', NULL, '{"ar": "لقد حلّ ذلك مشكلتي! شكرًا جزيلاً.", "en": "That solved my problem! Thank you very much.", "fr": "Cela a résolu mon problème ! Merci beaucoup.", "pt": "Isso resolveu o meu problema! Muito obrigado."}', true, '2026-04-24 11:51:32.950343+00', '2026-05-13 14:15:35.351475+00');
INSERT INTO "public"."fsu_agencies" ("id", "country_id", "dg_name", "dg_message", "dg_photo_url", "fsu_name", "agency_type", "created_at", "updated_at", "latitude", "longitude", "headquarters", "contact_phone", "contact_email") VALUES
	('008af2f0-780b-486a-a2c5-bf76ce4edfef', 'd3077782-c322-400c-8a2c-51b8fbd2a628', 'M. Gilles Thierry Beugré', '{"ar": "مرحباً بكم في منصة USF-ADCA، وهي ثمرة عمل تعاوني نموذجي بين دولنا الأعضاء وشركائنا التقنيين.", "en": "Welcome to the USF-ADCA platform, the fruit of exemplary collaborative work between our Member States and our technical partners. As director in charge of radiocommunications, I am convinced that optimal spectrum management and infrastructure deployment are keys to achieving our universal connectivity goals.", "fr": "Bienvenue sur la plateforme USF-ADCA, fruit d''un travail collaboratif exemplaire entre nos États membres et nos partenaires techniques. En tant que directeur en charge des radiocommunications, je suis convaincu que la gestion optimale du spectre et le déploiement des infrastructures sont les clés pour atteindre nos objectifs de connectivité universelle.", "pt": "Bem-vindo à plataforma USF-ADCA, fruto de um trabalho colaborativo exemplar entre os nossos Estados-Membros e os nosos parceiros técnicos."}', 'https://digitalmag.ci/wp-content/uploads/2025/03/Gilles-Beugre-DG-de-lANSUT-LIA-nous-aide-a-determiner-les-investissements-strategiques-dans-la-couverture-telecoms-en-Cote-dIvoire-.jpg', 'ANSUT', 'agency', '2026-05-12 11:51:33.217808+00', '2026-05-12 11:51:33.217808+00', 5.3484, -4.0305, 'Abidjan, Cocody Riviera', '+225 27 22 41 41 41', 'info@ansut.ci'),
	('0f57f898-b361-4bca-9ff2-efff520e7bcf', 'd3077782-c322-400c-8a2c-51b8fbd2a628', 'M. Lakoun Ouattara', '{"ar": "التنظيم هو في قلب تطوير الاقتصاد الرقمي.", "en": "Regulation is at the heart of the digital economy''s development. At ARTCI, we ensure that telecommunications infrastructure is accessible to all, while guaranteeing healthy competition for the benefit of populations.", "fr": "La régulation est au cœur du développement de l''économie numérique. À l''ARTCI, nous veillons à ce que les infrastructures de télécommunications soient accessibles à tous, tout en garantissant une saine concurrence pour le bénéfice des populations.", "pt": "A regulação está no centro do desenvolvimento da economia digital."}', 'https://www.artci.ci/images/stories/articles/IMG_0046.JPG', 'ARTCI', 'regulator', '2026-05-12 11:51:33.217808+00', '2026-05-12 11:51:33.217808+00', 5.3324, -4.0194, 'Abidjan, Marcory Anoumabo', '+225 27 20 34 43 00', 'artci@artci.ci'),
	('96acb5b0-7feb-4aa6-b4eb-4fab61410c3d', '7eee4f15-e529-4095-bc82-9f3aa33a3d4b', 'M. John Omo', '{"ar": "الاتحاد الأفريقي للاتصالات فخور بدعم هذه المبادرة.", "en": "The African Telecommunications Union is proud to support this initiative. The harmonization of universal service policies across the continent is crucial to making Africa a prosperous digital society.", "fr": "L''Union Africaine des Télécommunications est fière de soutenir cette initiative. L''harmonisation des politiques de service universel à travers le continent est cruciale pour faire de l''Afrique une société numérique prospère.", "pt": "A União Africana de Telecomunicações orgulha-se de apoiar esta iniciativa."}', 'https://cdn.asp.events/CLIENT_Delinian_88510B86_A1E4_E5AE_E5572932A0001A1B/sites/itw-africa-2026/media/libraries/speakers/John-Omo.jpg', 'UAT (ATU)', 'institution', '2026-05-12 11:51:33.217808+00', '2026-05-12 11:51:33.217808+00', -1.2921, 36.8219, 'Nairobi, Kenya', '+254 20 232 2120', 'sg@atu-uat.africa'),
	('98651fdd-ecbd-4692-97b4-1ab59fbd1e04', '4866a87c-4369-499c-acbb-587e06748d7a', 'Mme Fatou Diallo', '{"ar": "تلتزم السنغال بحزم بالتحول الرقمي الشامل.", "en": "Senegal is resolutely committed to inclusive digital transformation. Our Universal Service Fund works every day so that every citizen can benefit from the opportunities offered by digital technology.", "fr": "Le Sénégal s''engage résolument dans la transformation numérique inclusive. Notre Fonds de Service Universel œuvre chaque jour pour que chaque citoyen puisse bénéficier des opportunités offertes par le numérique.", "pt": "O Senegal está resolutamente empenhado na transformação digital inclusiva."}', 'https://www.au-senegal.com/IMG/jpg/fatou1.jpg', 'FSU Sénégal', 'agency', '2026-05-12 11:51:33.217808+00', '2026-05-12 11:51:33.217808+00', 14.7167, -17.4677, 'Dakar, Sénégal', '+221 33 869 03 69', 'contact@fsu.sn'),
	('c47e364f-5363-49d7-8647-f2c2e5b19de3', 'd947b5eb-80bb-4265-afe4-adad4f36e4d4', 'M. Kwame Mensah', '{"ar": "من خلال الخدمة الشاملة، نقوم بسد الفجوة وتمكين المجتمعات.", "en": "Through universal service, we are bridging the gap and empowering communities. Our platform is a testament to the power of collaboration and shared vision for a digitally inclusive Africa.", "fr": "Grâce au service universel, nous comblons le fossé et autonomisons les communautés. Notre plateforme témoigne du pouvoir de la collaboration et d''une vision partagée pour une Afrique numériquement inclusive.", "pt": "Através do serviço universal, estamos a colmatar a lacuna e a capacitar as comunidades."}', 'https://macdanenergy.com/professional-african-engineer-portrait.jpg', 'GIFEC Ghana', 'agency', '2026-05-12 11:51:33.217808+00', '2026-05-12 11:51:33.217808+00', 5.6037, -0.1870, 'Accra, Ghana', '+233 30 266 1111', 'info@gifec.gov.gh');
